<?php try{$fields=db()->query('SELECT * FROM product_custom_fields ORDER BY sort_order,id')->fetchAll();}catch(Throwable $e){$fields=[];} try{$groups=db()->query('SELECT id,name FROM product_groups ORDER BY sort_order,name')->fetchAll();}catch(Throwable $e){$groups=[];} ?>
<div class="ao-hero-slim"><h2>Özelleştirilebilir Alanlar</h2><p>Sipariş sırasında ürün veya grup bazlı alınacak özel müşteri bilgilerini yönet.</p></div>
<div class="ao-grid two"><div class="ao-card"><h3>Yeni Özel Alan</h3><form method="post" action="<?= url('admin/product-center/custom-field-save') ?>" class="ao-form ao-form-grid"><?= csrf_field() ?><label>Alan Adı<input name="label" required placeholder="Uygulama adı"></label><label>Alan Anahtarı<input name="field_key" placeholder="app_name"></label><label>Alan Tipi<select name="field_type"><option value="text">Metin</option><option value="textarea">Çok satırlı metin</option><option value="select">Açılır liste</option><option value="checkbox">Checkbox</option><option value="file">Dosya yükleme</option><option value="date">Tarih</option><option value="number">Sayısal</option></select></label><label>Ürün Grubu<select name="group_id"><option value="0">Tüm gruplar</option><?php foreach($groups as $g): ?><option value="<?= (int)$g['id'] ?>"><?= e($g['name']) ?></option><?php endforeach; ?></select></label><label>Seçenekler<textarea name="options" placeholder="Her satıra bir seçenek"></textarea></label><label>Sıra<input name="sort_order" value="10"></label><label><input type="checkbox" name="is_required" value="1"> Zorunlu</label><label><input type="checkbox" name="is_active" value="1" checked> Aktif</label><div><button class="ao-btn">Kaydet</button></div></form></div><div class="ao-card"><h3>Kayıtlı Alanlar</h3><?php foreach($fields as $f): ?><div class="ao-list-card"><div class="ao-list-title"><span class="letter">#</span><div><h3><?= e($f['label']) ?></h3><small><?= e($f['field_key']) ?></small></div></div><span class="ao-pill"><?= e($f['field_type']) ?></span><span><?= !empty($f['is_required'])?'Zorunlu':'Opsiyonel' ?></span><span class="ao-pill <?= !empty($f['is_active'])?'green':'red' ?>"><?= !empty($f['is_active'])?'Aktif':'Pasif' ?></span><div class="ao-action-row"><a class="ao-btn small" href="<?= url('admin/product-center/custom-field-toggle?id='.(int)$f['id'].'&csrf_token='.csrf_token()) ?>">Aktif/Pasif</a><a data-confirm="Özel alan silinsin mi?" class="ao-btn small ao-mini-danger" href="<?= url('admin/product-center/custom-field-delete?id='.(int)$f['id'].'&csrf_token='.csrf_token()) ?>">Sil</a></div></div><?php endforeach; if(!$fields): ?><p class="ao-muted">Henüz özel alan yok.</p><?php endif; ?></div></div>
